public class OrderService {
    private final OrderRepository repo;
    private final EmailService emailSvc;

    public OrderService(OrderRepository repo, EmailService emailSvc) {
        this.repo = repo;
        this.emailSvc = emailSvc;
    }

    public Order placeOrder(Order order) {
        if (order.qty() <= 0) throw new IllegalArgumentException("Qty must be positive");
        Order saved = repo.save(order.withStatus(OrderStatus.PENDING));
        emailSvc.sendConfirmation(saved);
        return saved;
    }
}
