worked_example.final_code:
import org.junit.jupiter.api.*;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.*;
import org.mockito.junit.jupiter.MockitoExtension;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;
import static org.mockito.ArgumentMatchers.*;

@ExtendWith(MockitoExtension.class)
class OrderServiceTest {
    @Mock OrderRepository repo;
    @Mock EmailService emailSvc;
    @InjectMocks OrderService service;
    @Captor ArgumentCaptor<Order> captor;

    Order input  = new Order("Mouse", 2, 799.0, OrderStatus.NEW);
    Order saved  = new Order("Mouse", 2, 799.0, OrderStatus.PENDING).withId("ORD-001");

    @Test
    void placeOrder_validOrder_returnsWithId() {
        when(repo.save(any())).thenReturn(saved);
        Order result = service.placeOrder(input);
        assertEquals("ORD-001", result.getId());
        verify(repo).save(any()); verify(emailSvc).sendConfirmation(saved);
    }

    @Test
    void placeOrder_repoFails_emailNotSent() {
        when(repo.save(any())).thenThrow(new RuntimeException("DB error"));
        assertThrows(RuntimeException.class, () -> service.placeOrder(input));
        verify(emailSvc, never()).sendConfirmation(any());
    }

    @Test
    void placeOrder_zeroQty_noInteractions() {
        Order bad = new Order("Mouse", 0, 799.0, OrderStatus.NEW);
        assertThrows(IllegalArgumentException.class, () -> service.placeOrder(bad));
        verifyNoInteractions(repo, emailSvc);
    }

    @Test
    void placeOrder_capturesPendingOrder() {
        when(repo.save(any())).thenReturn(saved);
        service.placeOrder(input);
        verify(repo).save(captor.capture());
        assertEquals(OrderStatus.PENDING, captor.getValue().getStatus());
    }

    @Test
    void placeOrder_saveBeforeEmail() {
        when(repo.save(any())).thenReturn(saved);
        service.placeOrder(input);
        InOrder inOrder = inOrder(repo, emailSvc);
        inOrder.verify(repo).save(any());
        inOrder.verify(emailSvc).sendConfirmation(saved);
    }
}
